module top_module(clk, rst, en, out);input clk, rst, en;
    output [3:0] out;

    reg [3:0] count;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
    begin
        if (rst)
            count <= 4'd0;
        else if (en)
            count <= count + 1;
    end

    assign out = count;
endmodule
